parameters.jsCode:
const staticData = $getWorkflowStaticData('global');
if (!staticData.seenCmsIds) staticData.seenCmsIds = [];
const seen = staticData.seenCmsIds;

const items = $input.all();
const newItems = [];

for (const item of items) {
  const id = item.json.link || item.json.guid;
  if (!id || seen.includes(id)) continue;
  seen.push(id);
  newItems.push({
    json: {
      id: id,
      title: item.json.title || '',
      content: item.json.contentSnippet || item.json.content || '',
      link: item.json.link || '',
      pubDate: item.json.pubDate || item.json.isoDate || ''
    }
  });
}

if (seen.length > 5000) staticData.seenCmsIds = seen.slice(-5000);

return newItems;

const response = $input.first().json;
let raw = '';
try {
  raw = response.candidates[0].content.parts[0].text;
} catch (e) {
  return { qualified: false, error: 'bad response' };
}
raw = raw.replace(/```json/g, '').replace(/```/g, '').trim();
try {
  return JSON.parse(raw);
} catch (e) {
  return { qualified: false, error: 'parse error', raw: raw };
}

